            ExerciseItem(prompt: "Դուք անհայտ համարից զանգ եք ստանում, որտեղ պնդում են, որ շահել եք վիճակախաղով, և խնդրում են ձեր բանկային տվյալները։ Ի՞նչ պետք է անեք։", options: ["Անմիջապես տալ նրանց ձեր տվյալները", "Անջատել հեռախոսը և ոչ մի անձնական տվյալ չհայտնել", "Խնդրել նրանց հետո զանգահարել", "Զանգահարել ընտանիքին տոնելու համար"], correctAnswer: "Անջատել հեռախոսը և ոչ մի անձնական տվյալ չհայտնել", explanation: "Անհայտ անձանց կողմից բանկային տվյալների հարցումները հաճախ խարդախություն են։"),
            ExerciseItem(prompt: "Դուք ձեզ թույլ և գլխապտույտ եք զգում տաք սենյակում կանգնած ժամանակ։ Ի՞նչ պետք է անեք։", options: ["Շարունակել կանգնել և փակել աչքերը", "Անմիջապես նստել և մի քիչ ջուր խմել", "Վազել լոգարան", "Պտտվել տեղում"], correctAnswer: "Անմիջապես նստել և մի քիչ ջուր խմել", explanation: "Նստելը կանխում է վայր ընկնելը, իսկ ջուրն օգնում է վերականգնել ուժերը։"),
            ExerciseItem(prompt: "Դուք տեսնում եք, որ ջուր է հոսում խոհանոցի լվացարանի տակից։ Ո՞րն է առաջին բանը, որ պետք է անեք։", options: ["Զանգահարել ներկարարին", "Դույլ դնել հոսքի տակ ջուրը հավաքելու համար", "Ավելի ուշ սրբել խոհանոցի հատակը", "Անջատել լույսերը"], correctAnswer: "Դույլ դնել հոսքի տակ ջուրը հավաքելու համար", explanation: "Դույլ դնելը կանխում է հատակի ջրով վնասվելը մինչև խնդիրը կարգավորվի։"),
            ExerciseItem(prompt: "Ձեզ հրավիրել են ընթրիքի, բայց դուք չեք կարող գնալ։ Ի՞նչ պետք է անեք։", options: ["Պարզապես չգնալ", "Նախապես տեղեկացնել հյուրընկալողին, որ չեք կարող մասնակցել", "Ուշանալ առանց զգուշացնելու", "Նվեր ուղարկել պատասխանելու փոխարեն"], correctAnswer: "Նախապես տեղեկացնել հյուրընկալողին, որ չեք կարող մասնակցել", explanation: "Հյուրընկալին նախօրոք տեղեկացնելը քաղաքավարի է և օգնում է նրանց ծրագրերը փոխել։"),
            ExerciseItem(prompt: "Դուք պատահաբար կոտրում եք դեկորատիվ ծաղկամանը ընկերոջ տանը։ Ո՞րն է ճիշտ արձագանքը։", options: ["Թաքցնել կտորները բազմոցի տակ", "Ներողություն խնդրել և առաջարկել փոխարինել այն", "Ձևացնել, թե դուք չեք արել", "Մեղադրել շանը"], correctAnswer: "Ներողություն խնդրել և առաջարկել փոխարինել այն", explanation: "Ազնվությունն ու վնասը փոխհատուցելու պատրաստակամությունը պատասխանատու քայլ է։"),
            ExerciseItem(prompt: "Դուք չեք կարողանում գտնել ձեր տան բանալիները և փակվել եք դրսում։ Ո՞րն է լավագույն քայլը։", options: ["Ջարդել պատուհանը ներս մտնելու համար", "Զանգահարել ընտանիքի անդամին, ով ունի պահեստային բանալի, կամ փականագործին", "Հավերժ սպասել պատշգամբում", "Հարվածել դռանը"], correctAnswer: "Զանգահարել ընտանիքի անդամին, ով ունի պահեստային բանալի, կամ փականագործին", explanation: "Պահեստային բանալի ունեցողին կամ մասնագետին դիմելն ամենաանվտանգ տարբերակն է։"),
            ExerciseItem(prompt: "Դուք նկատում եք, որ փողոցի լույսերը միացված են, բայց ձեր տունը էլեկտրաէներգիա չունի։ Ի՞նչ պետք է անեք։", options: ["Ստուգել ինքնաշխատ անջատիչների վահանակը", "Նոր հեռուստացույց գնել", "Անմիջապես գնալ քնելու", "Զանգահարել ոստիկանություն"], correctAnswer: "Ստուգել ինքնաշխատ անջատիչների վահանակը", explanation: "Անջատիչների վահանակի ստուգումն օգնում է հասկանալ՝ արդյոք խնդիրը տեղային է, թե համընդհանուր։"),
            ExerciseItem(prompt: "Դուք տեսնում եք, որ տարեց հարևանը դժվարությամբ է տանում ծանր գնումների տոպրակները։ Ի՞նչ պետք է անեք։", options: ["Արագ անցնել նրանց կողքով", "Առաջարկել օգնել նրանց տանել տոպրակները", "Լուսանկարել նրանց", "Ասել նրանց ավելի արագ քայլել"], correctAnswer: "Առաջարկել օգնել նրանց տանել տոպրակները", explanation: "Օգնություն առաջարկելը հարգանքի և աջակցության դրսևորում է։"),
            ExerciseItem(prompt: "Դուք սուրճից մի կում եք անում և հասկանում, որ այն չափազանց տաք է ու այրում է ձեր բերանը։ Ի՞նչ պետք է անեք։", options: ["Արագ խմել մնացածը", "Զգուշորեն թքել այն և սառը ջուր խմել", "Բարձր գոռալ", "Շպրտել բաժակը"], correctAnswer: "Զգուշորեն թքել այն և սառը ջուր խմել", explanation: "Սառը ջուրը մեղմացնում է այրվածքի ցավը և թուլացնում տհաճությունը։"),
            ExerciseItem(prompt: "Բժիշկը ձեզ նոր դեղ է նշանակում, բայց դուք չեք հասկանում, թե ինչպես պետք է այն ընդունել։ Ի՞նչ պետք է անեք։", options: ["Գուշակել դեղաչափը", "Խնդրել դեղագործին կամ բժշկին բացատրել ձեզ", "Չընդունել դեղը", "Փնտրել այն սոցիալական ցանցերում"], correctAnswer: "Խնդրել դեղագործին կամ բժշկին բացատրել ձեզ", explanation: "Մասնագետները միակ հավաստի աղբյուրն են դեղերի ընդունման հրահանգների համար։"),
            ExerciseItem(prompt: "Դուք պատահաբար կարմիր գինի եք թափում ընկերոջ սպիտակ գորգի վրա։ Ի՞նչ պետք է անեք։", options: ["Աթոռ դնել հետքի վրա", "Ներողություն խնդրել և անմիջապես օգնել մաքրել այն", "Շուտ հեռանալ խնջույքից", "Ասել նրանց, որ դա խաղողի հյութ էր"], correctAnswer: "Ներողություն խնդրել և անմիջապես օգնել մաքրել այն", explanation: "Հետքն անմիջապես մաքրելը կարող է կանխել գորգի երկարատև վնասումը։"),
            ExerciseItem(prompt: "Դուք լսում եք, որ ձեր ծխի ազդանշանային սարքը յուրաքանչյուր րոպե մեկ կարճ ձայնային ազդանշան է արձակում։ Ի՞նչ է սա նշանակում։", options: ["Կրակ կա", "Մարտկոցը թույլ է և պետք է փոխարինվի", "Սարքը փչացել է", "Ոչինչ"], correctAnswer: "Մարտկոցը թույլ է և պետք է փոխարինվի", explanation: "Պարբերական կարճ ազդանշանները նշանակում են, որ մարտկոցը թուլացել է։"),
            ExerciseItem(prompt: "Դուք վարում եք մեքենան և տեսնում եք փարոսիկներով արտակարգ իրավիճակների մեքենա ձեր հետևում։ Ի՞նչ պետք է անեք։", options: ["Արագացնել ընթացքը նրանից առաջ անցնելու համար", "Մեքենան կանգնեցնել ճանապարհի եզրին և անվտանգ կանգնել", "Անմիջապես կանգնել գծի մեջտեղում", "Անտեսել այն"], correctAnswer: "Մեքենան կանգնեցնել ճանապարհի եզրին և անվտանգ կանգնել", explanation: "Մեքենան ճանապարհի եզրին կանգնեցնելը թույլ է տալիս արտակարգ ծառայություններին անցնել։"),
            ExerciseItem(prompt: "Դուք նամակ եք ստանում ձեր բանկից, որտեղ խնդրում են սեղմել հղմանը՝ գաղտնաբառը հաստատելու համար։ Ի՞նչ պետք է անեք։", options: ["Սեղմել հղմանը և մուտքագրել գաղտնաբառը", "Ջնջել նամակը կամ ուղղակիորեն կապվել բանկի հետ պաշտոնական հեռախոսահամարով", "Ուղարկել այն ձեր ընկերներին", "Պատասխանել նամակին գաղտնաբառով"], correctAnswer: "Ջնջել նամակը կամ ուղղակիորեն կապվել բանկի հետ պաշտոնական հեռախոսահամարով", explanation: "Բանկերը երբեք էլեկտրոնային նամակներով գաղտնաբառ չեն հարցնում։"),
            ExerciseItem(prompt: "Դուք մայթին գտնում եք քսակ, որի մեջ կա գումար և անձնագիր։ Ի՞նչ պետք է անեք։", options: ["Պահել գումարը և դեն գցել քսակը", "Հանձնել այն ոստիկանությանը կամ փորձել կապվել տիրոջ հետ անձնագրի միջոցով", "Թողնել այն մայթին", "Տալ այն անծանոթին"], correctAnswer: "Հանձնել այն ոստիկանությանը կամ փորձել կապվել տիրոջ հետ անձնագրի միջոցով", explanation: "Կորած իրերը ոստիկանությանը կամ տիրոջը վերադարձնելը պատասխանատու քայլ է։"),
            ExerciseItem(prompt: "Ձեր ծխի ազդանշանային սարքը միանում է բարձր, շարունակական ձայնով։ Ի՞նչ պետք է անեք։", options: ["Անտեսել այն և սպասել մինչև դադարի", "Ստուգել հնարավոր հրդեհը և անհրաժեշտության դեպքում ապահով դուրս գալ շենքից", "Անմիջապես փոխել մարտկոցները", "Գնալ քնելու"], correctAnswer: "Ստուգել հնարավոր հրդեհը և անհրաժեշտության դեպքում ապահով դուրս գալ շենքից", explanation: "Շարունակական ազդանշանը նախազգուշացնում է հնարավոր հրդեհի մասին և պահանջում է շուտափույթ տարհանում։")
        ]
    )

}
